import{_ as a,o as t,c as o,ag as d}from"./chunks/framework.CAXxHpAX.js";const u=JSON.parse('{"title":"OpenCode 配置指南","description":"","frontmatter":{},"headers":[],"relativePath":"apps/opencode.md","filePath":"apps/opencode.md"}'),i={name:"apps/opencode.md"};function l(n,e,r,h,c,p){return t(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="opencode-配置指南" tabindex="-1">OpenCode 配置指南 <a class="header-anchor" href="#opencode-配置指南" aria-label="Permalink to &quot;OpenCode 配置指南&quot;">​</a></h1><p>开源 AI 编程助手，终端中的智能编码伙伴</p><p>📋 简介</p><p>OpenCode 是一款开源的 AI 编程助手，可在终端、IDE 或桌面环境中辅助编写、调试和改进代码。支持原生终端 TUI 界面、多会话并行、75+ 模型提供商接入，是命令行开发者的理想工具。</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><table tabindex="0"><thead><tr><th>资源</th><th>地址</th></tr></thead><tbody><tr><td>OpenCode 项目</td><td><a href="https://github.com/opencode-ai/opencode" target="_blank" rel="noreferrer">https://github.com/opencode-ai/opencode</a></td></tr></tbody></table><h2 id="功能特点" tabindex="-1">功能特点 <a class="header-anchor" href="#功能特点" aria-label="Permalink to &quot;功能特点&quot;">​</a></h2><ul><li>✅ 原生终端 TUI：专为命令行开发者设计，高效流畅</li><li>✅ 智能 LSP 加载：自动加载正确的语言服务器，提升上下文理解</li><li>✅ 多会话并行：支持多个会话同时运行，互不干扰</li><li>✅ 会话链接共享：可分享会话链接给他人协作</li><li>✅ 75+ 模型支持：支持多种模型提供商，包括本地模型</li><li>✅ 多平台支持：终端 CLI、桌面应用（Beta）、IDE 扩展</li></ul><h2 id="安装与配置" tabindex="-1">安装与配置 <a class="header-anchor" href="#安装与配置" aria-label="Permalink to &quot;安装与配置&quot;">​</a></h2><h3 id="第一步-安装-opencode" tabindex="-1">第一步：安装 OpenCode <a class="header-anchor" href="#第一步-安装-opencode" aria-label="Permalink to &quot;第一步：安装 OpenCode&quot;">​</a></h3><p>打开终端，运行以下命令全局安装 OpenCode：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opencode-ai</span></span></code></pre></div><p>安装完成后，在终端输入 <code>opencode</code> 命令，若出现 TUI 界面则安装成功。</p><h3 id="第二步-安装-cc-switch" tabindex="-1">第二步：安装 CC-Switch <a class="header-anchor" href="#第二步-安装-cc-switch" aria-label="Permalink to &quot;第二步：安装 CC-Switch&quot;">​</a></h3><p>查看 CC-Switch 配置工具文档，下载并安装 CC-Switch 到本地。</p><h3 id="第三步-添加-ikuncode-供应商" tabindex="-1">第三步：添加 IkunCode 供应商 <a class="header-anchor" href="#第三步-添加-ikuncode-供应商" aria-label="Permalink to &quot;第三步：添加 IkunCode 供应商&quot;">​</a></h3><ol><li>选择配置项</li></ol><p>打开 CC-Switch，上方配置项选择 <code>OpenCode</code>，然后点击 添加供应商 按钮。</p><ol start="2"><li>填写供应商信息</li></ol><p>按以下说明配置各项参数：</p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>预设供应商</td><td>选择 <code>IkunCode</code></td></tr><tr><td>供应商标识</td><td>自定义名称，如 <code>IkunCode-Claude</code></td></tr><tr><td>接口格式</td><td>Claude 模型选 <code>Anthropic</code>；GPT 模型选 <code>OpenAI</code>；Gemini 模型选 <code>Google (Gemini)</code></td></tr><tr><td>API Key</td><td>填入你在 IkunCode 控制台创建的 Key</td></tr><tr><td>额外选项</td><td>填写 <code>{&quot;setCacheKey&quot;:true}</code></td></tr></tbody></table><p>💡 支持的分组</p><p>根据你需要的模型类型，选择正确分组的 API Key：</p><ul><li>Claude 系列：只允许逆向分组</li><li>GPT 系列：Codex 分组</li><li>Gemini 系列：Gemini 分组</li></ul><p>请在创建专属 Key 时选择对应分组。</p><h2 id="验证配置" tabindex="-1">验证配置 <a class="header-anchor" href="#验证配置" aria-label="Permalink to &quot;验证配置&quot;">​</a></h2><ol><li>重新打开终端，输入 <code>opencode</code> 运行</li><li>输入 <code>/models</code> 命令，检查配置的渠道是否出现在模型列表中</li><li>如果能看到你添加的模型，说明配置成功</li></ol><p>开始愉快地编码吧！🎉</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="安装时提示-npm-未找到" tabindex="-1">安装时提示 npm 未找到？ <a class="header-anchor" href="#安装时提示-npm-未找到" aria-label="Permalink to &quot;安装时提示 npm 未找到？&quot;">​</a></h3><p>请先安装 Node.js 环境，参考 Node.js 环境安装文档。</p><h3 id="模型列表中看不到配置的渠道" tabindex="-1">模型列表中看不到配置的渠道？ <a class="header-anchor" href="#模型列表中看不到配置的渠道" aria-label="Permalink to &quot;模型列表中看不到配置的渠道？&quot;">​</a></h3><ul><li>确认 CC-Switch 中已正确保存配置</li><li>重启终端后再次运行 <code>opencode</code></li><li>检查 API Key 是否填写正确</li></ul><h3 id="更多问题" tabindex="-1">更多问题 <a class="header-anchor" href="#更多问题" aria-label="Permalink to &quot;更多问题&quot;">​</a></h3><p>请查看 FAQ 或联系售后支持。</p>',35)])])}const b=a(i,[["render",l]]);export{u as __pageData,b as default};
